mapper.select:
select mpc.id, mpc.meal_plan_id, mpc.customer_id, mpc.customer_name, mpc.phone, cp.customer_code, mpc.order_id, mpc.parent_package_id, mpc.child_package_id, mpc.status, mpc.is_verified, mpc.verification_time, mpc.verification_operator, mpc.fail_reason, mpc.meat_required_count, mpc.veg_required_count, mpc.include_soup, mpc.include_rice, mpc.supplementary_main_count, mpc.supplementary_side_count, mpc.supplementary_veg_count, mpc.supplementary_rice_count, mpc.supplementary_soup_count, cp.special_requirements, cp.production_date, mpc.create_by, mpc.update_by, mpc.deleted, mpc.create_time, mpc.update_time from meal_plan_customer mpc left join customer_profile cp on mpc.customer_id = cp.id where mpc.deleted = 0 and mpc.meal_plan_id in
#{mealPlanId}
order by mpc.meal_plan_id asc, mpc.id asc

select mpc.order_id as orderId, count(*) as scheduledCount from meal_plan_customer mpc join meal_plan mp on mpc.meal_plan_id = mp.id where mpc.deleted = 0 and mp.deleted = 0 and ( (#{mealType} = 'BREAKFAST' and mp.meal_type = 'BREAKFAST') or (#{mealType} in ('LUNCH', 'DINNER') and mp.meal_type in ('LUNCH', 'DINNER')) ) and mpc.order_id in
#{orderId}
group by mpc.order_id

select mpc.order_id as orderId, count(*) as scheduledCount from meal_plan_customer mpc join meal_plan mp on mpc.meal_plan_id = mp.id where mpc.deleted = 0 and mp.deleted = 0 and mpc.order_id in
#{orderId}
group by mpc.order_id

select mpc.order_id as orderId, count(*) as scheduledCount from meal_plan_customer mpc join meal_plan mp on mpc.meal_plan_id = mp.id where mpc.deleted = 0 and mp.deleted = 0 and mpc.status = 1 and mp.record_date = #{recordDate} and (mpc.is_verified = 0 or mpc.is_verified is null) and mpc.order_id in
#{orderId}
group by mpc.order_id

select distinct mpc.customer_id as customerId, mp.record_date as recordDate, mp.meal_type as mealType from meal_plan_customer mpc join meal_plan mp on mpc.meal_plan_id = mp.id where mpc.deleted = 0 and mp.deleted = 0 and mpc.status = 1 and mp.record_date >= #{startDate} and mp.record_date <= #{endDate} and mpc.customer_id in
#{customerId}
order by mpc.customer_id asc, mp.record_date asc, mp.meal_type asc

select current_rec.id from meal_plan_customer current_rec join meal_plan current_plan on current_plan.id = current_rec.meal_plan_id where current_rec.deleted = 0 and current_plan.deleted = 0 and current_rec.status = 1 and current_rec.id in
#{customerPlanId}
and not exists ( select 1 from meal_plan_customer previous_rec join meal_plan previous_plan on previous_plan.id = previous_rec.meal_plan_id where previous_rec.deleted = 0 and previous_plan.deleted = 0 and previous_rec.status = 1 and previous_rec.order_id = current_rec.order_id and previous_plan.meal_type = current_plan.meal_type and ( previous_plan.record_date < current_plan.record_date or (previous_plan.record_date = current_plan.record_date and previous_rec.id < current_rec.id) ) )

select mpc.order_id as orderId, mp.meal_type as mealType, count(*) as scheduledCount from meal_plan_customer mpc join meal_plan mp on mpc.meal_plan_id = mp.id where mpc.deleted = 0 and mp.deleted = 0 and mpc.status = 1 and mp.record_date = #{recordDate} and mpc.order_id in
#{orderId}
group by mpc.order_id, mp.meal_type
